#!/usr/bin/env perl
use strict;
use warnings;

my $config_file = 'validation_patterns.conf';
my %patterns;

sub load_patterns_from_config {
    my ($file) = @_;
    return unless -f $file;
    
    open my $fh, '<', $file or die "Cannot open config file: $!";
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
        
        if ($line =~ /^(\w+)\s*=\s*(.+)$/) {
            my ($name, $pattern) = ($1, $2);
            $patterns{$name} = $pattern;
        }
    }
    close $fh;
}

sub validate_string {
    my ($string, $pattern) = @_;
    
    my $regex = eval { qr/$pattern/ };
    if ($@) {
        print "Error compiling pattern: $@\n";
        return 0;
    }
    
    return $string =~ /$regex/;
}

sub validate_with_eval {
    my ($string, $user_pattern) = @_;
    
    my $result = eval "\$string =~ /$user_pattern/";
    if ($@) {
        print "Error in pattern evaluation: $@\n";
        return 0;
    }
    
    return $result;
}

sub interactive_mode {
    print "=== Flexible Validation System ===\n\n";
    
    while (1) {
        print "\nOptions:\n";
        print "1. Validate string with pattern\n";
        print "2. Add custom pattern\n";
        print "3. List available patterns\n";
        print "4. Test with user-provided pattern\n";
        print "5. Exit\n";
        print "Choose option: ";
        
        my $choice = <STDIN>;
        chomp $choice;
        
        if ($choice == 1) {
            print "Enter string to validate: ";
            my $string = <STDIN>;
            chomp $string;
            
            print "Enter pattern name or custom pattern: ";
            my $pattern_input = <STDIN>;
            chomp $pattern_input;
            
            my $pattern = $patterns{$pattern_input} || $pattern_input;
            
            if (validate_string($string, $pattern)) {
                print "✓ String matches pattern\n";
            } else {
                print "✗ String does not match pattern\n";
            }
        }
        elsif ($choice == 2) {
            print "Enter pattern name: ";
            my $name = <STDIN>;
            chomp $name;
            
            print "Enter regex pattern: ";
            my $pattern = <STDIN>;
            chomp $pattern;
            
            $patterns{$name} = $pattern;
            print "Pattern '$name' added successfully\n";
        }
        elsif ($choice == 3) {
            print "\nAvailable patterns:\n";
            foreach my $name (sort keys %patterns) {
                print "  $name: $patterns{$name}\n";
            }
        }
        elsif ($choice == 4) {
            print "Enter string to test: ";
            my $string = <STDIN>;
            chomp $string;
            
            print "Enter user pattern: ";
            my $user_pattern = <STDIN>;
            chomp $user_pattern;
            
            if (validate_with_eval($string, $user_pattern)) {
                print "✓ String matches user pattern\n";
            } else {
                print "✗ String does not match user pattern\n";
            }
        }
        elsif ($choice == 5) {
            print "Exiting...\n";
            last;
        }
        else {
            print "Invalid option\n";
        }
    }
}

sub batch_validate {
    my ($test_file) = @_;
    
    open my $fh, '<', $test_file or die "Cannot open test file: $!";
    
    while (my $line = <$fh>) {
        chomp $line;
        next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
        
        if ($line =~ /^TEST:\s*(.+?)\s*\|\s*(.+)$/) {
            my ($string, $pattern_name) = ($1, $2);
            my $pattern = $patterns{$pattern_name};
            
            if ($pattern) {
                my $result = validate_string($string, $pattern);
                print "Testing '$string' against '$pattern_name': ";
                print $result ? "PASS\n" : "FAIL\n";
            } else {
                print "Pattern '$pattern_name' not found\n";
            }
        }
    }
    
    close $fh;
}

sub dynamic_pattern_compile {
    my ($pattern_string) = @_;
    
    my $compiled = eval "qr/$pattern_string/";
    
    if ($@) {
        die "Failed to compile pattern: $@";
    }
    
    return $compiled;
}

sub validate_with_dynamic_pattern {
    my ($string, $pattern_string) = @_;
    
    my $regex = dynamic_pattern_compile($pattern_string);
    return $string =~ $regex;
}

sub main {
    load_patterns_from_config($config_file);
    
    $patterns{email} ||= '^[\w\.\-]+@[\w\.\-]+\.\w+$';
    $patterns{phone} ||= '^\d{3}-\d{3}-\d{4}$';
    $patterns{zipcode} ||= '^\d{5}(-\d{4})?$';
    $patterns{username} ||= '^[a-zA-Z0-9_]{3,16}$';
    $patterns{url} ||= '^https?://[\w\.\-]+';
    
    if (@ARGV && $ARGV[0] eq '--batch' && $ARGV[1]) {
        batch_validate($ARGV[1]);
    } elsif (@ARGV && @ARGV >= 2) {
        my $string = $ARGV[0];
        my $pattern_input = $ARGV[1];
        my $pattern = $patterns{$pattern_input} || $pattern_input;
        
        if (validate_string($string, $pattern)) {
            print "Match: YES\n";
            exit 0;
        } else {
            print "Match: NO\n";
            exit 1;
        }
    } else {
        interactive_mode();
    }
}

